css:
.loader {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      min-width: 68px;
      min-height: 22px;
    }
    .loader i {
      display: block;
      width: 11px;
      height: 11px;
      border-radius: 50%;
      background: var(--loader-color);
      animation: dotPulse 0.7799999999999999s ease-in-out infinite;
    }
    .loader i:nth-child(1) { animation-delay: 0.00s; }
.loader i:nth-child(2) { animation-delay: 0.12s; }
.loader i:nth-child(3) { animation-delay: 0.24s; }
.loader i:nth-child(4) { animation-delay: 0.36s; }
    @keyframes dotPulse { 0%, 80%, 100% { opacity: .25; transform: scale(.7); } 40% { opacity: 1; transform: scale(1); } }
